return results;

// Extrae todos los campos de un AttachedDocument DIAN (XML interior) para registrar en Supabase.
// Sin dependencias externas — compatible con n8n task runner.

function getText(xml, tag) {
  if (!xml) return null;
  const t = tag.replace(':', '\\:');
  const m = xml.match(new RegExp('<' + t + '(?:\\s[^>]*)?>([^<]*)<\\/' + t + '>'));
  return (m && m[1].trim()) ? m[1].trim() : null;
}

function getAttr(xml, tag, attr) {
  if (!xml) return null;
  const t = tag.replace(':', '\\:');
  const m = xml.match(new RegExp('<' + t + '[^>]*\\s' + attr + '="([^"]*)"'));
  return m ? m[1] : null;
}

function getBlock(xml, tag) {
  if (!xml) return null;
  const t = tag.replace(':', '\\:');
  const re = new RegExp('<' + t + '(?:\\s[^>]*)?>[\\s\\S]*?<\\/' + t + '>', 's');
  const m = xml.match(re);
  return m ? m[0] : null;
}

function getBlocks(xml, tag) {
  if (!xml) return [];
  const t = tag.replace(':', '\\:');
  const re = new RegExp('<' + t + '(?:\\s[^>]*)?>[\\s\\S]*?<\\/' + t + '>', 'gs');
  return [...xml.matchAll(re)].map(m => m[0]);
}

function toNum(str) {
  if (str === null || str === undefined) return null;
  const n = parseFloat(str);
  return isNaN(n) ? null : n;
}

function adVal(node) {
  if (!node) return null;
  if (typeof node === 'string') return node;
  if (typeof node === 'object' && '_' in node) return String(node._);
  return null;
}

function mapTipoDocumento(code) {
  const map = { '01': 'factura', '02': 'factura', '03': 'factura', '91': 'nota credito', '92': 'nota credito' };
  return map[code] ?? 'factura';
}

function mapTipoOperacion(code) {
  return (code === 'CO' || !code) ? 'nacional' : 'internacional';
}

const results = [];

for (const item of $input.all()) {
  const ad = item.json?.AttachedDocument;

  if (!ad) {
    results.push({ json: { tiene_xml_interior: false } });
    continue;
  }

  const numero_factura         = adVal(ad?.['cbc:ParentDocumentID']);
  const cufe                   = adVal(ad?.['cac:ParentDocumentLineReference']?.['cac:DocumentReference']?.['cbc:UUID']);
  const fecha_emision          = adVal(ad?.['cac:ParentDocumentLineReference']?.['cac:DocumentReference']?.['cbc:IssueDate']);
  const senderPartyTax         = ad?.['cac:SenderParty']?.['cac:PartyTaxScheme'];
  const proveedor_id           = adVal(senderPartyTax?.['cbc:CompanyID']);
  const razon_social_proveedor = adVal(senderPartyTax?.['cbc:RegistrationName']);

  const descNode = ad?.['cac:Attachment']?.['cac:ExternalReference']?.['cbc:Description'];
  let innerXml = typeof descNode === 'string' ? descNode
               : (descNode?.['_'] ?? descNode?.['#text'] ?? null);

  if (!innerXml?.trim()) {
    results.push({
      json: {
        tiene_xml_interior: false,
        numero_factura, cufe, fecha_emision, proveedor_id, razon_social_proveedor,
      }
    });
    continue;
  }

  innerXml = innerXml.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1');

  const tipo_documento_code = getText(innerXml, 'cbc:InvoiceTypeCode')
    ?? getText(innerXml, 'cbc:CreditNoteTypeCode')
    ?? getText(innerXml, 'cbc:DebitNoteTypeCode');
  const tipo_documento = mapTipoDocumento(tipo_documento_code);

  const fecha_vencimiento =
    getText(innerXml, 'cbc:DueDate') ??
    getText(getBlock(innerXml, 'cac:PaymentMeans') ?? '', 'cbc:PaymentDueDate');

  const tipo_operacion_code = getText(getBlock(innerXml, 'sts:InvoiceSource') ?? '', 'cbc:IdentificationCode');
  const tipo_operacion = mapTipoOperacion(tipo_operacion_code);

  const qr_dian = getText(innerXml, 'sts:QRCode');

  const supplierBlock   = getBlock(innerXml, 'cac:AccountingSupplierParty') ?? '';
  const supplierParty   = getBlock(supplierBlock, 'cac:Party') ?? '';
  const supplierAddress = getBlock(getBlock(supplierParty, 'cac:PhysicalLocation') ?? '', 'cac:Address') ?? '';
  const supplierContact = getBlock(supplierParty, 'cac:Contact') ?? '';
  const supplierTax     = getBlock(supplierParty, 'cac:PartyTaxScheme') ?? '';

  const proveedor_data = {
    nit:                 proveedor_id,
    razon_social:        razon_social_proveedor,
    direccion:           getText(getBlock(supplierAddress, 'cac:AddressLine') ?? '', 'cbc:Line'),
    ciudad:              getText(supplierAddress, 'cbc:CityName'),
    telefono:            getText(supplierContact, 'cbc:Telephone'),
    email:               getText(supplierContact, 'cbc:ElectronicMail'),
    regimen_tributario:  getText(getBlock(supplierTax, 'cac:TaxScheme') ?? '', 'cbc:ID') === '01' ? 'comun' : 'simplificado',
    tipo_contribuyente:  getText(supplierBlock, 'cbc:AdditionalAccountID') === '1' ? 'PJ' : 'PN',
  };

  const lmtBlock            = getBlock(innerXml, 'cac:LegalMonetaryTotal') ?? '';
  const valor_total_factura = toNum(getText(lmtBlock, 'cbc:PayableAmount'));
  let valor_base_gravable   = toNum(getText(lmtBlock, 'cbc:TaxExclusiveAmount'));

  const lineTag      = innerXml.includes('<cac:CreditNoteLine') ? 'cac:CreditNoteLine'
                     : innerXml.includes('<cac:DebitNoteLine')  ? 'cac:DebitNoteLine'
                     : 'cac:InvoiceLine';
  const firstLineIdx = innerXml.indexOf('<' + lineTag);
  const headerXml    = firstLineIdx > 0 ? innerXml.substring(0, firstLineIdx) : innerXml;

  let iva_valor              = null;
  let impuesto_consumo_valor = 0;

  for (const ttBlock of getBlocks(headerXml, 'cac:TaxTotal')) {
    for (const subBlock of getBlocks(ttBlock, 'cac:TaxSubtotal')) {
      const catBlock = getBlock(subBlock, 'cac:TaxCategory') ?? '';
      const schemeId = getText(getBlock(catBlock, 'cac:TaxScheme') ?? '', 'cbc:ID');
      const pct      = parseFloat(getText(catBlock, 'cbc:Percent') ?? '-1');

      if (schemeId === '01' || pct === 0 || pct === 5 || pct === 19) {
        if (iva_valor === null)           iva_valor           = toNum(getText(subBlock, 'cbc:TaxAmount'));
        if (valor_base_gravable === null) valor_base_gravable = toNum(getText(subBlock, 'cbc:TaxableAmount'));
      } else if (schemeId === '22' || pct === 4 || pct === 8) {
        impuesto_consumo_valor = toNum(getText(subBlock, 'cbc:TaxAmount')) ?? 0;
      }
    }
    if (iva_valor === null) iva_valor = toNum(getText(ttBlock, 'cbc:TaxAmount'));
  }

  const qtyTag = lineTag === 'cac:CreditNoteLine' ? 'cbc:CreditedQuantity'
               : lineTag === 'cac:DebitNoteLine'  ? 'cbc:DebitedQuantity'
               : 'cbc:InvoicedQuantity';

  const concepto_detallado = getBlocks(innerXml, lineTag).map((lineXml, idx) => {
    const cantidad      = toNum(getText(lineXml, qtyTag)) ?? 1;
    const unidad_medida = getAttr(lineXml, qtyTag, 'unitCode') ?? 'UN';

    const valor_unitario_sin_impuestos = toNum(getText(getBlock(lineXml, 'cac:Price') ?? '', 'cbc:PriceAmount'));
    const valor_total_sin_impuestos    = toNum(getText(lineXml, 'cbc:LineExtensionAmount'));

    const descBlock = getBlocks(lineXml, 'cac:AllowanceCharge')
                        .find(b => getText(b, 'cbc:ChargeIndicator') === 'false');
    const descuento_total          = toNum(getText(descBlock ?? '', 'cbc:Amount')) ?? 0;
    const descTarifaRaw            = toNum(getText(descBlock ?? '', 'cbc:MultiplierFactorNumeric')) ?? 0;
    const descuento_tarifa         = descTarifaRaw <= 1 ? descTarifaRaw * 100 : descTarifaRaw;
    const descuento_valor_unitario = cantidad > 0 ? descuento_total / cantidad : 0;

    let iva_tarifa = 0, iva_total_linea = 0;
    let impuesto_consumo_tarifa = null, impuesto_consumo_val_linea = 0;

    lineIvaLoop: for (const ttBlock of getBlocks(lineXml, 'cac:TaxTotal')) {
      for (const subBlock of getBlocks(ttBlock, 'cac:TaxSubtotal')) {
        const catBlock = getBlock(subBlock, 'cac:TaxCategory') ?? '';
        const schemeId = getText(getBlock(catBlock, 'cac:TaxScheme') ?? '', 'cbc:ID');
        const pct      = parseFloat(getText(catBlock, 'cbc:Percent') ?? '-1');

        if (schemeId === '01' || pct === 0 || pct === 5 || pct === 19) {
          iva_tarifa      = pct >= 0 ? pct : 0;
          iva_total_linea = toNum(getText(subBlock, 'cbc:TaxAmount'))
                         ?? toNum(getText(ttBlock, 'cbc:TaxAmount')) ?? 0;
          break lineIvaLoop;
        } else if (schemeId === '22' || pct === 4 || pct === 8) {
          impuesto_consumo_tarifa    = pct;
          impuesto_consumo_val_linea = toNum(getText(subBlock, 'cbc:TaxAmount')) ?? 0;
        }
      }
      if (iva_total_linea === 0) iva_total_linea = toNum(getText(ttBlock, 'cbc:TaxAmount')) ?? 0;
    }

    const iva_valor_unitario              = cantidad > 0 ? iva_total_linea / cantidad : 0;
    const impuesto_consumo_valor_unitario = cantidad > 0 ? impuesto_consumo_val_linea / cantidad : 0;
    const valor_total_con_impuestos       = (valor_total_sin_impuestos ?? 0) + iva_total_linea + impuesto_consumo_val_linea;
    const valor_unitario_con_descuento    = (valor_unitario_sin_impuestos ?? 0) - descuento_valor_unitario;
    const valor_unitario_con_impuestos    = valor_unitario_con_descuento + iva_valor_unitario + impuesto_consumo_valor_unitario;

    const itemBlock   = getBlock(lineXml, 'cac:Item') ?? '';
    const descripcion = getText(itemBlock, 'cbc:Description') ?? '';
    const codigo =
      getText(getBlock(itemBlock, 'cac:StandardItemIdentification') ?? '', 'cbc:ID') ??
      getText(getBlock(itemBlock, 'cac:SellersItemIdentification')  ?? '', 'cbc:ID') ?? '';

    return {
      item_numero: parseInt(getText(lineXml, 'cbc:ID') ?? String(idx + 1)),
      descripcion, codigo, cantidad, unidad_medida,
      valor_unitario_sin_impuestos, valor_total_sin_impuestos,
      descuento_tarifa, descuento_valor_unitario, descuento_total,
      iva_tarifa, iva_valor_unitario,
      impuesto_consumo_tarifa, impuesto_consumo_valor_unitario,
      valor_unitario_con_descuento, valor_unitario_con_impuestos, valor_total_con_impuestos,
    };
  });

  results.push({
    json: {
      tiene_xml_interior: true,
      proveedor_data,
      numero_factura, cufe, fecha_emision, proveedor_id, razon_social_proveedor,
      tipo_documento, fecha_vencimiento,
      valor_base_gravable,
      iva_valor: iva_valor ?? 0,
      impuesto_consumo_valor, valor_total_factura,
      tipo_operacion, concepto_detallado,
      retencion_fuente_valor: 0, retencion_iva_valor: 0, retencion_ica_valor: 0, otros_cargos: null,
      centro_costo_id: null, transaccion_id: null,
      cuenta_contable: 'pendiente', tipo_gasto: 'pendiente', estado_pago: 'pendiente',
      asignacion_pendiente: true, registro_items: 'pendiente',
      observaciones: null, archivo_factura_url: null,
      metadata: {
        fuente_extraccion: 'xml_dian',
        tipo_documento_dian: tipo_documento_code,
        qr_dian: qr_dian,
      },
    }
  });
}

return results;

const outputItems = [];
for (const item of $input.all()) {
  if (item.binary) {
    for (const binaryKey of Object.keys(item.binary)) {
      outputItems.push({
        json: {
          originalItemIndex: $input.all().indexOf(item),
          binaryKey: binaryKey,
          fileName: item.binary[binaryKey].fileName || binaryKey,
          mimeType: item.binary[binaryKey].mimeType || 'application/octet-stream',
          fileSize: item.binary[binaryKey].fileSize || 0
        },
        binary: { data: item.binary[binaryKey] }
      });
    }
  }
}
return outputItems;

let results = [];
for (item of items) {
    for (key of Object.keys(item.binary)) {
        results.push({
            json: { fileName: item.binary[key].fileName, mimeType: item.binary[key].mimeType },
            binary: { data: item.binary[key] }
        });
    }
}
return results;

const items = $input.all();
return items.map(item => {
  const { fileName, ...facturaData } = item.json;
  return { json: { data: [ facturaData, { fileName } ] } };
});
